function initLanguage(){try{const browserLang=getBrowserLanguage(),currentLang=document.documentElement.lang||"en";browserLang&&browserLang!==currentLang&&changeLanguage(browserLang)}catch(error){console.error("Language initialization failed:",error)}}function getBrowserLanguage(){const savedLang=localStorage.getItem("language");if(savedLang)return savedLang;const browserLang=navigator.language.split("-")[0];return["de","en","tr"].includes(browserLang)?browserLang:"en"}function changeLanguage(lang){if(!["de","en","tr"].includes(lang))return void console.error("Unsupported language:",lang);localStorage.setItem("language",lang);const currentUrl=new URL(window.location);currentUrl.searchParams.set("lang",lang),window.location.href=currentUrl.toString()}document.addEventListener("DOMContentLoaded",initLanguage);